import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";
export const useSalesStore = defineStore("sales", {
  state: () => ({
    sales: [],
    barcode_query: "",
    pageCount: 1,
    params: {
      sortBy: [],
      sortDesc: [],
      page: 1,
      itemsPerPage: 1,
    },
    table_loading: false,
    loading: false,
    retrieve_loading: false,
  }),

  actions: {
    async reset_table() {
      this.params.page = 1;
      this.params.sortBy = [];
      this.params.sortDesc = [];
      this.barcode_query = "";
      this.pageCount = 1;
      this.table_loading = false;
      this.sales = [];
    },

    async get_sales() {
      const data = this.params;
      this.table_loading = true;
      try {
        const skip = (data.page - 1) * data.itemsPerPage;
        const limit = data.itemsPerPage;

        let query = "";
        if (this.barcode_query && this.barcode_query.length > 0) {
          query = `&query=${this.barcode_query}`;
        }

        const response = await axios.get(
          `${server}/api/get_sales?skip=${skip}&limit=${limit}${query}`
        );

        this.pageCount = response.data.count;
        this.sales = response.data.result;
        this.table_loading = false;

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },

    async add_sales(data) {
      const snackbar = useSnackbarStore();

      this.loading = true;
      try {
        const response = await axios.post(`${server}/api/add_sales`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });
        this.loading = false;

        snackbar.showMessage({
          color: "#21ce8f",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },

    async retrieve_item(data) {
      const snackbar = useSnackbarStore();

      this.retrieve_loading = true;
      try {
        const response = await axios.post(`${server}/api/retrieve_item`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });
        this.retrieve_loading = false;

        snackbar.showMessage({
          color: "#21ce8f",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        const updatedSale = response.data.result[0];
        const index = this.sales.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales.splice(index, 1, updatedSale);
        }

        return response;
      } catch (error) {
        this.retrieve_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async retrieve_all_items(data) {
      const snackbar = useSnackbarStore();

      this.retrieve_loading = true;
      try {
        const response = await axios.post(
          `${server}/api/retrieve_all_items`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        const updatedSale = response.data.result[0];
        const index = this.sales.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales.splice(index, 1, updatedSale);
        }

        this.retrieve_loading = false;

        snackbar.showMessage({
          color: "#21ce8f",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.retrieve_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
  },

  getters: {},
});
