<template>
  <v-snackbar
    dir="rtl"
    v-model="snackbarStore.snackbar"
    :multi-line="true"
    :color="snackbarStore.snack_message?.color || 'primary'"
    timeout="4000"
    variant="outlined"
  >
    <h4
      class="font-weight-black"
      style="font-family: 'Cairo', sans-serif"
      v-for="(text, index) in (snackbarStore.snack_message?.text || '').split(
        '\n'
      )"
      :key="index"
    >
      {{ index == 0 ? "" : index + "-" }} {{ text }}
    </h4>
    <template v-slot:action="{ attrs }">
      <v-btn text v-bind="attrs" icon class="ml-3">
        <Icon
          :icon="snackbarStore.snack_message?.icon"
          :color="snackbarStore.snack_message?.color"
          width="30"
        />
      </v-btn>
    </template>
  </v-snackbar>
</template>

<script setup>
import { useSnackbarStore } from "@/stores/snackbar";

const snackbarStore = useSnackbarStore();
</script>
